import { DB_CLIENTS, VIRTUAL_CLIENT_MODULE_ID } from '../consts.js';
import type { VitePlugin } from '../utils.js';

type VitePluginDBClientParams = {
	connectToRemote: boolean;
	mode: 'node' | 'web';
};

function getRemoteClientModule(mode: 'node' | 'web') {
	switch (mode) {
		case 'web':
			return `export { createClient } from '${DB_CLIENTS.web}';`;
		case 'node':
		default:
			return `export { createClient } from '${DB_CLIENTS.node}';`;
	}
}

function getLocalClientModule(mode: 'node' | 'web') {
	switch (mode) {
		case 'node':
		case 'web':
		default:
			return `export { createClient } from '${DB_CLIENTS.local}';`;
	}
}

const resolved = '\0' + VIRTUAL_CLIENT_MODULE_ID;

export function vitePluginDbClient(params: VitePluginDBClientParams): VitePlugin {
	return {
		name: 'virtual:astro:db-client',
		enforce: 'pre',
		resolveId: {
			filter: {
				id: new RegExp(`^${VIRTUAL_CLIENT_MODULE_ID}$`),
			},
			handler() {
				return resolved;
			},
		},
		load: {
			filter: {
				id: new RegExp(`^${resolved}$`),
			},
			handler() {
				switch (params.connectToRemote) {
					case true:
						return getRemoteClientModule(params.mode);
					case false:
					default:
						// Local client is always available, even if not used.
						return getLocalClientModule(params.mode);
				}
			},
		},
	};
}

import type { AstroConfig, AstroIntegration, ContentEntryType, HookParameters } from 'astro';
import { getContentEntryType } from './content-entry-type.js';
import {
	loadMarkdocConfig,
	type MarkdocConfigResult,
	SUPPORTED_MARKDOC_CONFIG_FILES,
} from './load-config.js';
import type { MarkdocIntegrationOptions } from './options.js';

type SetupHookParams = HookParameters<'astro:config:setup'> & {
	// `contentEntryType` is not a public API
	// Add type defs here
	addContentEntryType: (contentEntryType: ContentEntryType) => void;
};

export default function markdocIntegration(options?: MarkdocIntegrationOptions): AstroIntegration {
	let markdocConfigResult: MarkdocConfigResult | undefined;
	let astroConfig: AstroConfig;
	return {
		name: '@astrojs/markdoc',
		hooks: {
			'astro:config:setup': async (params) => {
				const { updateConfig, addContentEntryType } = params as SetupHookParams;
				astroConfig = params.config;

				markdocConfigResult = await loadMarkdocConfig(astroConfig);

				addContentEntryType(
					await getContentEntryType({ markdocConfigResult, astroConfig, options }),
				);

				updateConfig({
					vite: {
						ssr: {
							external: ['@astrojs/markdoc/prism', '@astrojs/markdoc/shiki'],
						},
					},
				});
			},
			'astro:server:setup': async ({ server }) => {
				server.watcher.on('all', (_event, entry) => {
					if (SUPPORTED_MARKDOC_CONFIG_FILES.some((f) => entry.endsWith(f))) {
						server.restart();
					}
				});
			},
		},
	};
}

